import java.io.*;
public class NoFlush {
    public static void main(String[] args) throws Exception {
        FileOutputStream fos = new FileOutputStream("/tmp/data.ser");
        ObjectOutputStream oos = new ObjectOutputStream(fos);
        oos.writeObject("hello");
        // bug: oos never closed or flushed
        // data may remain in buffer and not be written to file
    }
}
